external_knowledge:
- "peak of literary stardom" refers to the highest average book rating;
- "shining brightly since the dawn of the new millennium" refers to books published from the year 2001 onwards;
- "publishers" are identified by their unique `publisher_id` and their `name`.

sql:
SELECT AVG(avg_ratings_per_publisher.avg_rating) AS overall_avg_rating
FROM (
  SELECT AVG(rating) AS avg_rating
  FROM books
  GROUP BY publisher_id
) AS avg_ratings_per_publisher;

SELECT T1.book_title || ' by ' || T2.first_name || ' ' || T2.last_name AS "Book Information"
FROM books T1
JOIN authors T2 ON T1.author_id = T2.author_id;

SELECT book_title
FROM books
WHERE rating = (
    SELECT MAX(rating)
    FROM books
);

